import{_ as a,c as o,o as r,aA as t}from"./chunks/framework.DPonWJ6h.js";const s="/previews/PR5389/assets/arrow_components.DgXiFCT5.png",m=JSON.parse('{"title":"arrows","description":"","frontmatter":{},"headers":[],"relativePath":"reference/plots/arrows.md","filePath":"reference/plots/arrows.md","lastUpdated":null}'),n={name:"reference/plots/arrows.md"};function i(d,e,c,h,l,p){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="arrows" tabindex="-1">arrows <a class="header-anchor" href="#arrows" aria-label="Permalink to &quot;arrows {#arrows}&quot;">​</a></h1><h1 id="arrows-2" tabindex="-1">arrows <a class="header-anchor" href="#arrows-2" aria-label="Permalink to &quot;arrows {#arrows-2}&quot;">​</a></h1><p><code>arrows</code> is deprecated. Use <a href="/previews/PR5389/reference/plots/arrows2d#arrows2d">arrows2d</a> or <a href="/previews/PR5389/reference/plots/arrows3d#arrows3d">arrows3d</a> instead.</p><p>Arrows are split into two plot types, <code>arrows2d</code> and <code>arrows3d</code>. They differ in the arrow markers they create - <code>arrows2d</code> creates 2D arrows and <code>arrows3d</code> creates 3D arrows. Both can be used with 2D and 3D coordinates.</p><h2 id="Arrow-Components-and-Details" tabindex="-1">Arrow Components &amp; Details <a class="header-anchor" href="#Arrow-Components-and-Details" aria-label="Permalink to &quot;Arrow Components &amp;amp; Details {#Arrow-Components-and-Details}&quot;">​</a></h2><p><img src="'+s+'" alt=""></p><h3 id="Arrow-Length" tabindex="-1">Arrow Length <a class="header-anchor" href="#Arrow-Length" aria-label="Permalink to &quot;Arrow Length {#Arrow-Length}&quot;">​</a></h3><p>The target size of each arrow is determined by its direction vector (second plot argument), <code>normalize</code> and <code>lengthscale</code>. From tail to tip, the length is given as <code>lengthscale * norm(direction)</code>. If <code>normalize = true</code> the direction is normalized first, i.e. the length becomes just <code>lengthscale</code>.</p><p>There is also the option to treat the second plot argument as the arrows endpoint with <code>argmode = :endpoint</code>. In this case the directions are determined as <code>direction = endpoint - startpoint</code> and then follow the same principles.</p><h3 id="Scaling" tabindex="-1">Scaling <a class="header-anchor" href="#Scaling" aria-label="Permalink to &quot;Scaling {#Scaling}&quot;">​</a></h3><p>Arrow markers are separated into 3 components, a tail, a shaft and a tip. Each component comes with a length and width/radius (2D/3D) which determines its size. In 2D the sizes are given in pixel units by default (dependent on <code>markerspace</code>). In 3D they are given in relative units if <code>markerscale = automatic</code> (default) or data space units scaled by <code>markerscale</code> otherwise. To fit arrows to the length determined by <code>directions</code>, <code>lengthscale</code> and <code>normalize</code>, the <code>shaftlength</code> varies between <code>minshaftlength</code> and <code>maxshaftlength</code> if it is not explicitly set. Outside of this range or if it is explicitly set, all arrow lengths and widths/radii are scaled by a common factor instead.</p><h3 id="Shapes" tabindex="-1">Shapes <a class="header-anchor" href="#Shapes" aria-label="Permalink to &quot;Shapes {#Shapes}&quot;">​</a></h3><p>The base shape of each component is given by the <code>tail</code>, <code>shaft</code> and <code>tip</code> attributes. For arrows2d these can be anything compatible with <code>poly</code>, e.g. a 2D mesh, Polygon or Vector of points. Each component should be defined in a 0..1 x -0.5..0.5 range, where +x is the direction of the arrow. The shape can also be constructed by a callback function <code>f(length, width, metrics)</code> returning something poly-compatible. It is given the final length and width of the component as well as the all the other final lengths and widths through metrics. For arrows3d they should be a mesh or GeometryPrimitive defined in a -0.5..0.5 x -0.5..0.5 x 0..1 range. Here +z is the direction of the arrow.</p>',13)])])}const f=a(n,[["render",i]]);export{m as __pageData,f as default};
